    cmd = bytes([0xcd, 0, 0, 0, 0, 0x06, 0x12]) + struct.pack('<HHHH', 0, 0, w - 1, h - 1) + bytes([0x00])
    assert len(cmd) == 16
    log("  blit: send CBW")
